INSERT INTO detections (
  rule_id, name, description, severity, platform,
  mitre_attack_id, mitre_tactic, mitre_technique,
  nist_controls, data_sources, query, query_language, tags,
  expected_alerts_per_day, expected_fp_rate, expected_mttd_hours,
  is_global, tenant_id, log_sources, device_types
) VALUES
('DET-0151', 'Many USB File Copies for User', 'Build a baseline of how many file copies each user does to USB media, and detect when a user copies an uncharacteristically large number of files.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1052', 'Exfiltration', 'Exfiltration Over Physical Medium', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DLP","Endpoint Detection and Response"}', '{"Data Loss Prevention","EDR","Endpoint"}'),
('DET-0152', 'Basic Malware Outbreak', 'Looks for the same malware occurring on multiple systems in a short period of time.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1189', 'Initial Access', 'Drive-by Compromise', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0153', 'Create or delete hidden shares using net.exe', 'This search looks for the creation or deletion of hidden shares using net.exe.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` count values(Processes.user) as user values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where (Processs.process_name=net.exe OR Processes.process_name=net1.exe) by Processes.process Processes.process_name Processes.dest | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)` | search (process=*share* OR process=*delete*)| regex process="\S+[$]"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0154', 'Unusually Long VPN Session', 'Detects unusually long VPN sessions, based on a user''s baseline and their peer group.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"IP Address Assignment"}', '{}'),
('DET-0155', 'Short Lived Admin Accounts', 'A technique used by attackers is to create an account, take some actions, and then delete it right away. This search will find those accounts on the local system.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1136', 'Defense Evasion', 'Create Account', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0156', 'Processes with Lookalike (typo) Filenames', 'To evade analysts, attackers will create a service with a name similar to that of a standard Windows service. This search looks for small differences. Idea from David Bianco, formerly of Sqrrl (http://detect-respond.blogspot.com/2016/11/hunting-for-malware-critical-process.html">link).Alert Volume: Very Low', 'INFO'::detection_severity, 'SPLUNK'::detection_platform, 'T1036', 'Defense Evasion', 'Masquerading', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0157', 'New User Taking Privileged Actions', 'Record when a user who hasn''t taken privileged actions before suddenly starts.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0158', 'Remote WMI Command Attempt', 'This search looks for wmic.exe being launched with parameters to operate on remote systems.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1047', 'Execution', 'Windows Management Instrumentation', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=wmic.exe  AND Processes.process= */node* by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0159', 'Attempt To Add Certificate To Untrusted Store', 'Attempt to add a certificate to the untrusted certificate store', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '| tstats `summariesonly` count min(_time) values(Processes.process) as process max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=certutil.exe (Processes.process=*-addstore* AND Processes.process=*disallowed* ) by Processes.parent_process Processes.process_name Processes.user | `drop_dm_object_name("Processes")` | `ctime(firstTime)`|`ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0160', 'Blacklisted IP Address', 'Generates anomalies for traffic that goes to Blacklisted IPs', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1094', 'Command and Control', 'Custom Command and Control Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0161', 'New Logon Type for User', 'Windows defines several logon types (Interactive, RemoteInteractive, Network, etc.). Established users rarely generate new logon types. This search will look for that scenario. (https://car.mitre.org/wiki/CAR-2013-02-012">MITRE CAR Reference)Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0162', 'AWS New API Call Per User', 'Looks for users that are using AWS APIs that they''ve never used before.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1260', 'Execution', 'Determine 3rd party infrastructure services', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0163', 'Multiple Outgoing Connections', 'Multiple Outgoing Connections', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1041', 'Exfiltration', 'Exfiltration Over Command and Control Channel', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0164', 'Geographically Improbable Access Detected against Category', 'To ensure you have a GDPR-mandated audit trail with individual accounts for each person, detect when the same account is logged into twice in a short period of time but from locations very far away, to a GDPR-tagged system.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Audit Trail","Audit Trail","AWS"}', '{"Identity Provider","Active Directory","Audit System","AWS Cloud"}'),
('DET-0165', 'In-Scope System with Windows Update Disabled', 'Any GDPR-tagged systems not receiving updates could jeopardize your GDPR status due to Article 32. Detect systems where the Windows Update service is disabled.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Patch Management"}', '{}'),
('DET-0166', 'Child Processes of Spoolsv.exe', 'This search looks for child processes of spoolsv.exe. This activity is associated with a POC privilege-escalation exploit associated with CVE-2018-8440. Spoolsv.exe is the process associated with the Print Spooler service in Windows and typically runs as SYSTEM.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1068', 'Privilege Escalation', 'Exploitation for Privilege Escalation', '{}', '{}', '| tstats `summariesonly` count values(Processes.process_name) as process_name values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.parent_process_name=spoolsv.exe AND Processes.process_name!=regsvr32.exe by Processes.dest Processes.parent_process Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0167', 'High Or Critical Priority Host With Malware Detected', 'Alerts when an infection is noted on a host with high or critical priority.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1189', 'Initial Access', 'Drive-by Compromise', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Anti-Virus / Anti-Malware"}', '{"Antivirus"}'),
('DET-0168', 'Registry Keys for Creating SHIM Databases', 'This search looks for registry activity associated with application compatibility shims, which can be leveraged by attackers for various nefarious purposes.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1138', 'Persistence', 'Application Shimming', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime FROM datamodel=Change_Analysis.All_Changes where All_Changes.object_category=registry AND (All_Changes.object_path="*CurrentVersion\\AppCompatFlags\\Custom*" OR All_Changes.object_path="*CurrentVersion\\AppCompatFlags\\InstalledSDB*") by All_Changes.dest, All_Changes.command, All_Changes.user, All_Changes.object, All_Changes.object_path | `drop_dm_object_name("All_Changes")`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0169', 'SIEM-E-TA000-XX-File with Samsam Extension', 'The search looks for file writes with extensions consistent with a SamSam ransomware attack.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'Execution', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime values(Filesystem.user) as user values(Filesystem.dest) as dest values(Filesystem.file_path) as file_path from datamodel=Endpoint.Filesystem by Filesystem.file_name | `drop_dm_object_name(Filesystem)` | `ctime(lastTime)` | `ctime(firstTime)`| rex field=file_name "(?<file_extension>\.[^\.]+)$" | search file_extension=.stubbin OR file_extension=.berkshire OR file_extension=.satoshi OR file_extension=.sophos OR file_extension=.keyxml', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0170', 'Windows Event Log Clearing Events', 'This use case looks for Windows event codes that indicate the Windows Audit Logs were tampered with.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0171', 'Uncommon Processes On Endpoint', 'This search looks for applications on the endpoint that you have marked as prohibited.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1015', 'Execution', 'Accessibility Features', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes by Processes.dest Processes.user Processes.process Processes.process_name | `ctime(firstTime)`| `ctime(lastTime)` | `drop_dm_object_name(Processes)` | `uncommon_processes`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0172', 'Spike in Downloaded Documents Per User from Salesforce.com', 'Salesforce.com contains the most critical information for many companies. This example tracks the number of documents downloaded per day per user, to detect exfiltration.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0173', 'Increase in Pages Printed', 'Find users who printed more pages than normal.Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1052', 'Exfiltration', 'Exfiltration Over Physical Medium', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"User Activity Audit"}', '{}'),
('DET-0174', 'SIEM-LM-TA000-XX-Significant Increase in Interactive Logons', 'Typically non-admin users will only interactively log into one system per day. A user who starts loggin into many can indicate account compromise and lateral movement. (https://car.mitre.org/wiki/CAR-2013-02-012">MITRE CAR Reference)Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Lateral Movement', 'Lateral Movement', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0175', 'Abnormally High Number of HTTP Method Events By Src', 'Alerts when a host has an abnormally high number of HTTP requests by http method.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1190', 'Initial Access', 'Exploit Public-Facing Application', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0176', 'Unrouteable Activity Detected', 'Alerts when activity to or from a host that is unrouteable is detected.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1046', 'Discovery', 'Network Service Scanning', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0177', 'New Application Accessing Salesforce.com API', 'Salesforce.com contains the most critical information for many companies. This search looks for users who connect to SFDC''s reporting API with new clients. Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0178', 'Detect Log Clearing With wevtutil', 'This use case looks for the wevutil process clearing the Windows Audit LogsAlert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0179', 'USN Journal Deletion', 'The fsutil.exe application is a legitimate Windows utility used to perform tasks related to the file allocation table (FAT) and NTFS file systems. The update sequence number (USN) change journal provides a log of all changes made to the files on the disk. This search looks for fsutil.exe deleting the USN journal.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1070', 'Defense Evasion', 'Indicator Removal on Host', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=fsutil.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)` | search process="*deletejournal*" AND process="*usn*"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0180', 'WMI Temporary Event Subscription', 'This search looks for the creation of WMI temporary event subscriptions.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1047', 'Execution', 'Windows Management Instrumentation', '{}', '{}', 'sourcetype="wineventlog:microsoft-windows-wmi-activity/operational" EventCode=5860 Temporary | rex field=Message "NotificationQuery =\s+(?<query>[^|^$]+)" | search query!="SELECT * FROM Win32_ProcessStartTrace WHERE ProcessName = ''wsmprovhost.exe''" AND query!="SELECT * FROM __InstanceOperationEvent WHERE TargetInstance ISA ''AntiVirusProduct'' OR TargetInstance ISA ''FirewallProduct'' OR TargetInstance ISA ''AntiSpywareProduct''" | stats count min(_time) as firstTime max(_time) as lastTime by ComputerName, query  | `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0181', 'Detect Excessive Account Lockouts From Endpoint', 'This search identifies endpoints that have caused a relatively high number of account lockouts in a short period.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Credential Access', 'Valid Accounts', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Change.All_Changes where nodename=All_Changes.Account_Management All_Changes.result="lockout" by All_Changes.dest All_Changes.result |`drop_dm_object_name("All_Changes")` |`drop_dm_object_name("Account_Management")`| `ctime(firstTime)` | `ctime(lastTime)` | search count > 5', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0182', 'Suspicious HTTP redirects', 'Detects sequences of HTTP requests within a short period of time that suggests infection has taken place.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1185', 'Collection', 'Man in the Browser', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0183', 'Healthcare Worker Opening More Patient Records Than Usual', 'If a healthcare worker views more patient records than normal or more than their peers, it could be a sign that their system is infected, or that they are exfiltrating patient data.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0184', 'Detect USB device insertion', 'The search is used to detect hosts that generate Windows Event ID 4663 for successful attempts to write to or read from a removable storage and Event ID 4656 for failures, which occurs when a USB drive is plugged in. In this scenario we are querying the Change_Analysis data model to look for Windows Event ID 4656 or 4663 where the priority of the affected host is marked as high in the ES Assets and Identity Framework.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1052', 'Exfiltration', 'Exfiltration Over Physical Medium', '{}', '{}', '| tstats `summariesonly` count earliest(_time) AS earliest latest(_time) AS latest from datamodel=Change_Analysis where (nodename = All_Changes) All_Changes.result="Removable Storage device" (All_Changes.result_id=4663 OR All_Changes.result_id=4656) (All_Changes.src_priority=high) by All_Changes.dest | `drop_dm_object_name("All_Changes")`| `ctime(earliest)`| `ctime(latest)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","DLP"}', '{"EDR","Endpoint","Data Loss Prevention"}'),
('DET-0185', 'Detect Many Unauthorized Access Attempts', 'Most login failures are due to failed passwords. Login failure to sensitive systems where the users simply aren''t authorized, though, can indicate malicious intent. Detect that.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0186', 'Suspicious Email Attachment Extensions', 'This search looks for emails that have attachments with suspicious file extensions.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1193', 'Initial Access', 'Spearphishing Attachment', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Email where All_Email.file_name="*" by All_Email.src_user, All_Email.file_name All_Email.message_id | `ctime(firstTime)` | `ctime(lastTime)` | `drop_dm_object_name("All_Email")` | `suspicious_email_attachments`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Email","Email"}', '{"Email Gateway","Mail Server"}'),
('DET-0187', 'Web Browsing to Unauthorized Sites', 'Detect users who are persistently attempting to violate your proxy policy.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1048', 'Exfiltration', 'Exfiltration Over Alternative Protocol', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0188', 'Multiple Box Login Errors', 'Detects outliers in the timeseries of Box login failures per Box user.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0189', 'Old Passwords in Use', 'Detect active accounts with passwords that haven''t been updated in more than 120 days.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1110', 'Credential Access', 'Brute Force', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0190', 'User Login with Local Credentials', 'Categorically, most interactive logins should use domain credentials. Detect when a new user logs on with local credentials that bypass most centralized logging and policy systems, but not Splunk!', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Privilege Escalation', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0191', 'Suspicious Reg.exe Process', 'This search looks for reg.exe being launched from a command prompt not started by the user. When a user launches cmd.exe, the parent process is usually explorer.exe. This search filters out those instances.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1112', 'Defense Evasion', 'Modify Registry', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Processes where Processes.parent_process_name != explorer.exe Processes.process_name =cmd.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest Processes.process_id Processes.parent_process_id | `drop_dm_object_name("Processes")` | `ctime(firstTime)` | `ctime(lastTime)` | search [| tstats `summariesonly` count FROM datamodel=Endpoint.Processes where Processes.parent_process_name=cmd.exe Processes.process_name= reg.exe by Processes.parent_process_id Processes.dest Processes.process_name | `drop_dm_object_name("Processes")` | `ctime(firstTime)` | `ctime(lastTime)` | rename parent_process_id as process_id |dedup process_id| table process_id dest]', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0192', 'Large Web Upload', 'Uses a basic threshold to detect a large web upload, which could be exfiltration from malware or a malicious insider.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1041', 'Exfiltration', 'Exfiltration Over Command and Control Channel', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Proxy / NGFW"}', '{"Web Proxy","Next-Gen Firewall"}'),
('DET-0193', 'First Time Logon to New Server', 'Find users who logged into a new server for the first time.Alert Volume: Very High', 'CRITICAL'::detection_severity, 'SPLUNK'::detection_platform, 'T1021', 'Lateral Movement', 'Remote Services', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0194', 'Malicious AD Activity', 'Raises anomalies when the input data matches a set of predefined patterns in Microsoft Windows logs.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0195', 'Network Device Rebooted', 'Increases the risk score of network devices that have been rebooted.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1089', 'Defense Evasion', 'Disabling Security Tools', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Configuration Management"}', '{}'),
('DET-0196', 'Unusually Long Content-Type Length', 'This search looks for unusually long strings in the Content-Type http header that the client sends the server.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1320', 'Defense Evasion', 'Data Hiding', '{}', '{}', 'sourcetype=stream:http | eval cs_content_type_length = len(cs_content_type) | where cs_content_type_length > 100 | table endtime src_ip dest_ip cs_content_type_length cs_content_type url', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0197', 'Detect PsExec With accepteula Flag', 'This search looks for events where <code>PsExec.exe</code> is run with the <code>accepteula</code> flag in the command line. PsExec is a built-in Windows utility that enables you to execute processes on other systems. It is fully interactive for console applications. This tool is widely used for launching interactive command prompts on remote systems. Threat actors leverage this extensively for executing code on compromised systems. If an attacker is running PsExec for the first time, they will be prompted to accept the end-user license agreement (EULA), which can be passed as the argument <code>accepteula</code> within the command line.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = PsExec.exe Processes.process = "*accepteula*" by Processes.process_name Processes.dest  Processes.parent_process_name | `drop_dm_object_name(Processes)`| `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0198', 'SIEM-DE-None-XX-Remote Registry Key modifications', 'This search monitors for remote modifications to registry keys.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Defense Evasion', 'None', '{}', '{}', '| tstats `summariesonly` count values(Registry.registry_key_name) as registry_key_name values(Registry.registry_path) as registry_path min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Registry where  Registry.registry_path="\\\\*"  by Registry.dest , Registry.status, Registry.user | `ctime(lastTime)` | `ctime(firstTime)` | `drop_dm_object_name(Registry)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0199', 'Fake Windows Processes', 'This example finds processes normally run from Windows\System32 or Windows\SysWOW64, running from some other location. This can indicate a malicious process trying to hide as a legitimate process.Alert Volume: Low', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1036', 'Defense Evasion', 'Masquerading', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response","Windows Security"}', '{"EDR","Endpoint","Windows AD","Windows Endpoint"}'),
('DET-0200', 'SIEM-E-None-XX-Detect S3 access from a new IP', 'This search looks at S3 bucket-access logs and detects new or previously unseen remote IP addresses that have successfully accessed an S3 bucket.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Execution', 'None', '{}', '{}', 'sourcetype=aws:s3:accesslogs http_status=200  [search sourcetype=aws:s3:accesslogs http_status=200 | stats earliest(_time) as firstTime latest(_time) as lastTime by bucket_name remote_ip | inputlookup append=t previously_seen_S3_access_from_remote_ip.csv | stats min(firstTime) as firstTime, max(lastTime) as lastTime by bucket_name remote_ip | outputlookup previously_seen_S3_access_from_remote_ip.csv | eval newIP=if(firstTime >= relative_time(now(), "-70m@m"), 1, 0) | where newIP=1 | convert ctime(firstTime) ctime(lastTime) | table bucket_name remote_ip]| iplocation remote_ip |rename remote_ip as src_ip | table _time bucket_name src_ip City Country operation request_uri', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS","Web Server"}', '{"Audit System","AWS Cloud"}')
ON CONFLICT (rule_id) DO NOTHING;